import kotlinx.coroutines.flow.Flow
import org.junit.After
import org.junit.Before
import org.junit.Test

class UnifiedInboxConfiguratorTest {

    @Before
    fun setUp() {
        K9.isShowUnifiedInbox = false
    }

    @After
    fun tearDown() {
        K9.isShowUnifiedInbox = false
    }

    @Test
    fun `configureUnifiedInbox should not enable unified inbox when only one account exists`() {
        val accountManager = createFakeAccountManager(accountCount = 1)
        val configurator = UnifiedInboxConfigurator(accountManager)

        configurator.configureUnifiedInbox()

        assertThat(K9.isShowUnifiedInbox).isFalse()
    }

    @Test
    fun `configureUnifiedInbox should enable unified inbox when exactly two accounts exist`() {
        val accountManager = createFakeAccountManager(accountCount = 2)
        val configurator = UnifiedInboxConfigurator(accountManager)

        configurator.configureUnifiedInbox()

        assertThat(K9.isShowUnifiedInbox).isTrue()
    }

    @Test
    fun `configureUnifiedInbox should not change setting when more than two accounts exist`() {
        val accountManager = createFakeAccountManager(accountCount = 3)
        val configurator = UnifiedInboxConfigurator(accountManager)

        configurator.configureUnifiedInbox()

        assertThat(K9.isShowUnifiedInbox).isFalse()
    }

    @Test
    fun `configureUnifiedInbox should preserve disabled unified inbox when adding third account`() {
        // Simulate user having disabled unified inbox after having 2 accounts
        K9.isShowUnifiedInbox = false

        val accountManager = createFakeAccountManager(accountCount = 3)
        val configurator = UnifiedInboxConfigurator(accountManager)

        configurator.configureUnifiedInbox()

        // Setting should remain false (user's preference preserved)
        assertThat(K9.isShowUnifiedInbox).isFalse()
    }

    @Test
    fun `configureUnifiedInbox should preserve enabled unified inbox when adding third account`() {
        // Simulate unified inbox being enabled (user's preference)
        K9.isShowUnifiedInbox = true

        val accountManager = createFakeAccountManager(accountCount = 3)
        val configurator = UnifiedInboxConfigurator(accountManager)

        configurator.configureUnifiedInbox()

        // Setting should remain true (user's preference preserved)
        assertThat(K9.isShowUnifiedInbox).isTrue()
    }

    @Test
    fun `configureUnifiedInbox should not enable unified inbox when no accounts exist`() {
        val accountManager = createFakeAccountManager(accountCount = 0)
        val configurator = UnifiedInboxConfigurator(accountManager)

        configurator.configureUnifiedInbox()

        assertThat(K9.isShowUnifiedInbox).isFalse()
    }

